var fences = '```';
var repoState = $('Read Repo State').item.json.stdout || 'no repo state';
var sourceFiles = $('Read Source Files').item.json.stdout || 'no source files';
var model = $env.OLLAMA_CODE_MODEL || $env.OLLAMA_CHAT_MODEL || 'nemotron-3-nano:latest';
var system = 'You are local-coder, an autonomous coding agent for the qwen-agent-collective repository.\n\n'
  + 'Task: implement ONE small, concrete improvement from the Recommended Next Work Slice in the latest report.\n\n'
  + 'OUTPUT FORMAT: respond with ONLY a POSIX sh script fenced in ' + fences + 'sh ... ' + fences + '.\n'
  + 'Rules:\n'
  + '- Script runs as: cd /home/cbk/qwen-agent-collective && sh script.sh\n'
  + '- POSIX sh only (no bash arrays, no [[ ]], no bashisms)\n'
  + '- Allowed: cat, printf, mkdir -p, cp, mv\n'
  + '- FORBIDDEN: rm, git push, git reset, git commit, pip install, apt-get, curl, wget\n'
  + '- Max 1-3 file changes, no deletions\n'
  + '- If nothing safe to do: ' + fences + 'sh\n# no-op\n' + fences;
var user = '=== REPO STATE & LATEST REPORT ===\n'
  + repoState.slice(0, 7000)
  + '\n\n=== SOURCE FILES ===\n'
  + sourceFiles.slice(0, 5000)
  + '\n\nImplement the Recommended Next Work Slice. Output ONLY the sh script.';
return [{ json: { model: model, messages: [{ role: 'system', content: system }, { role: 'user', content: user }] } }];

var raw = ($input.first().json.choices || [])[0];
raw = raw ? raw.message.content : '';
var match = raw.match(/```(?:sh|bash|shell)?\n?([\s\S]*?)```/);
var script = match ? match[1].trim() : raw.trim();
if (!script || /^#\s*no.?op\s*$/im.test(script)) {
  return [{ json: { script: '', script_b64: '', safe: true, noop: true, reason: 'no-op', raw: raw } }];
}
var blocked = ['rm -rf', 'rm -r', ' rm ', 'git push', 'git reset', 'git commit', 'apt-get', 'pip install', '> /etc/', '> /usr/', '> /bin/', ':(){', 'mkfs'];
var hit = '';
for (var i = 0; i < blocked.length; i++) {
  if (script.indexOf(blocked[i]) !== -1) { hit = blocked[i]; break; }
}
if (hit) {
  return [{ json: { script: '', script_b64: '', safe: false, noop: true, reason: 'blocked: ' + hit, raw: raw } }];
}
if (script.indexOf('/home/') !== -1 && script.indexOf('/home/cbk/qwen-agent-collective') === -1) {
  return [{ json: { script: '', script_b64: '', safe: false, noop: true, reason: 'path outside repo', raw: raw } }];
}
var script_b64 = Buffer.from(script, 'utf8').toString('base64');
return [{ json: { script: script, script_b64: script_b64, safe: true, noop: false, reason: 'ok', raw: raw } }];

